sql:
SELECT analysis_date, AVG(p_value) AS average_p_value
FROM statistical_measures
GROUP BY analysis_date;

SELECT tumor_type_name
FROM tumor_types
WHERE tumor_type_id = 1;

SELECT patient_id, COUNT(sample_id) AS number_of_samples
FROM samples
GROUP BY patient_id;

